CanDisturbanceSequence   sequence;
long                     result;

//Clear sequence
sequence.Clear();

//configure a sequence one bit long and send a dominant bit
result = sequence.AppendToSequence(320, 'd');

if(result == 1)
{
  result= canDisturbanceTriggerNow(deviceID, sequence);

